const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;

function computeBasePremium(items: any[]): number {
  const mainItemPremium = items
    .filter((item: any) => !COMPONENT_TYPES.has(item.type))
    .reduce((sum: number, item: any) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  const componentPremium = Object.entries(componentCounts).reduce(
    (sum, [type, count]) =>
      sum + (count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUM[type] ?? 0)),
    0
  );

  return mainItemPremium + componentPremium;
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    if (step.op === "quote") {
      const basePremium = computeBasePremium(step.items);
      const itemSurcharges = step.items.reduce((sum: number, item: any) => {
        const itemBase = BASE_PREMIUM[item.type] ?? 0;
        let surcharge = 0;
        if (item.cursed) surcharge += itemBase * CURSED_SURCHARGE_RATE;
        return sum + surcharge;
      }, 0);
      const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE);
      return { premium };
    }
  });
  return { results };
}

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("should return 5G premium for empty item list (processing fee only)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("should return 115G for a single sword (100G base + 10G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should return 71G for a single amulet (60G base + 6G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should return 93G for a staff and 49G for a potion", () => {
      const staffResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(staffResult.results[0]).toEqual({ premium: 93 });

      const potionResult = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      expect(potionResult.results[0]).toEqual({ premium: 49 });
    });
    it("should return 33G for a single rune (25G base + 2.5G first insurance + 5G fee, ceil)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should return 71G for 3 runes (60G block base + 6G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should return 60G for 2 runes (50G base + 5G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 60 });
    });
    it("should return 115G for 4 runes (100G base, no block + 10G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should return 88G for 2 runes + 1 moonstone (75G base + 7.5G first insurance + 5G fee, ceil)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 88 });
    });
    it("should return 137G for 3 runes + 3 moonstones (120G two blocks + 12G first insurance + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" }, { type: "rune" }, { type: "rune" },
              { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
            ],
          },
        ],
      });
      expect(result.results[0]).toEqual({ premium: 137 });
    });
  });

  describe("Quote - premium modifiers", () => {
    it("should add 50% surcharge for cursed items on the item base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
